sql:
SELECT COUNT(DISTINCT address_id) AS total_verified_addresses
FROM address_quality_metrics
WHERE is_verified = 1;

external_knowledge:
; Audit refers to a quality check process on addresses; 
; Passing an audit implies the address meets certain quality standards; 
; A match refers to a successful association or link between address-related data; 
; Match confidence level is a measure of how reliable the match is; 
; Average match confidence level is a measure of overall reliability for all matches associated with an address.

sql:
SELECT address_id, quality_score
FROM address_quality_metrics
ORDER BY quality_score DESC;

SELECT is_verified, COUNT(*) AS address_count
FROM address_quality_metrics
GROUP BY is_verified;

SELECT user_id, COUNT(request_id) AS verification_requests
FROM address_verification_requests
GROUP BY user_id;

SELECT address_id, COUNT(variation) AS variation_count
FROM address_variations
GROUP BY address_id;

external_knowledge:
; Verified addresses refer to addresses with is_verified = 1 in the address_quality_metrics table; 
; The highest match scores are determined by the match_rank = 1 from the address_matches table;
; Quality score differences are calculated as the difference between the maximum and minimum quality scores for each address;
; Access counts and error counts are aggregated from the address_verification_requests and address_error_reports tables, respectively.
